// Helper to simplify AND/OR of two fcmp with constants and same variable.
static Value *simplifyAndOrOfFCmpsWithConstants(FCmpInst *Cmp0, FCmpInst *Cmp1,
                                                bool IsAnd) {
  // Look for this pattern: {and/or} (fcmp X, C0), (fcmp X, C1)).
  // Both comparisons must have the same operand order (variable on left,
  // constant on right). This assumes canonical form.
  if (Cmp0->getOperand(0) != Cmp1->getOperand(0))
    return nullptr;

  const APFloat *C0, *C1;
  if (!match(Cmp0->getOperand(1), m_APFloat(C0)) ||
      !match(Cmp1->getOperand(1), m_APFloat(C1)))
    return nullptr;

  // Only handle comparisons with the same predicate for now.
  if (Cmp0->getPredicate() != Cmp1->getPredicate())
    return nullptr;

  // For ordered predicates, we can determine subset relationship based on
  // constant ordering.
  auto Pred = Cmp0->getPredicate();
  APFloat::cmpResult CR = C0->compare(*C1);
  if (CR == APFloat::cmpUnordered) {
    // One or both constants are NaN? Not possible for normal constants.
    return nullptr;
  }
  bool C0LessThanC1 = CR == APFloat::cmpLessThan;
  bool C0EqualC1 = CR == APFloat::cmpEqual;

  // Determine which comparison is stricter (smaller set of true values).
  // For less-than family (olt, ult, ole, ule), smaller constant is stricter.
  // For greater-than family (ogt, ugt, oge, uge), larger constant is stricter.
  // For equality family (oeq, une, etc.) we cannot simplify without more analysis.
  switch (Pred) {
  case FCmpInst::FCMP_OLT:
  case FCmpInst::FCMP_ULT:
  case FCmpInst::FCMP_OLE:
  case FCmpInst::FCMP_ULE:
    // Less-than family.
    if (C0EqualC1) {
      // Same constant, either comparison is equivalent.
      return Cmp0;
    }
    if (C0LessThanC1) {
      // C0 is smaller, stricter.
      return IsAnd ? Cmp0 : Cmp1;
    } else {
      // C1 is smaller.
      return IsAnd ? Cmp1 : Cmp0;
    }
    break;
  case FCmpInst::FCMP_OGT:
  case FCmpInst::FCMP_UGT:
  case FCmpInst::FCMP_OGE:
  case FCmpInst::FCMP_UGE:
    // Greater-than family.
    if (C0EqualC1) {
      return Cmp0;
    }
    if (C0LessThanC1) {
      // C0 is smaller, less strict for greater-than.
      return IsAnd ? Cmp1 : Cmp0;
    } else {
      return IsAnd ? Cmp0 : Cmp1;
    }
    break;
  default:
    // For equality/not-equality, we cannot simplify without considering NaN.
    // TODO: handle (X == C0) || (X == C1) etc.
    return nullptr;
  }
}

